// Convierte dd/m/yyyy -> yyyy-mm-dd
function toISO(d) {
  if (!d) return null;
  // admite "22/9/2026" o "22-9-2026"
  const m = String(d).trim().replace(/-/g,'/').match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
  if (!m) return d; // si ya viene ISO, lo deja igual
  const [_, dd, mm, yyyy] = m;
  const pad = s => s.toString().padStart(2,'0');
  return `${yyyy}-${pad(mm)}-${pad(dd)}`;
}

// Normaliza color (primera letra mayúscula)
function normColor(s){
  if(!s) return s;
  const t = String(s).trim().toLowerCase();
  return t.charAt(0).toUpperCase() + t.slice(1);
}

// Construir la lista de casos desde los items de entrada
const casos = items.map(({ json }) => {
  const j = json;

  // la hoja parece tener "cambio " con espacio al final
  const rawCambio = j.cambio ?? j['cambio'] ?? false;

  return {
    case_id: String(j.case_id ?? j.id ?? ''),
    empleado_nombre: String(j.empleado_nombre ?? '').trim(),
    color_actual: normColor(j.color_actual),
    fase_actual: String(j.fase_actual ?? '').trim(),
    fecha_ultima_revision: toISO(j.fecha_ultima_revision),
    fecha_proxima_revision: toISO(j.fecha_proxima_revision),
    cambio: (typeof rawCambio === 'boolean')
              ? rawCambio
              : String(rawCambio).trim().toLowerCase() === 'true'
  };
});

// VERSION: número derivado del contenido (cambia si cambian casos)
// (hash simple; si preferís, podés usar Date.now())
const signature = casos.map(c =>
  `${c.case_id}|${c.color_actual}|${c.fase_actual}|${c.fecha_ultima_revision}|${c.fecha_proxima_revision}|${c.cambio}`
).join('~');
let h = 0; for (const ch of signature) { h = ((h<<5)-h) + ch.charCodeAt(0); h |= 0; }
const version = Math.abs(h);

// Nombre del “drive” (cámbialo o léelo de otra celda si querés)
const drive_name = 'Casos Medicina Laboral – Septiembre';

return [
  {
    json: {
      drive_name,
      version,
      casos
    }
  }
];
